const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || webhookData;
const { projectId, scope, architecture, runId } = body;

const strideCategories = [
  { id: 'S', name: 'Spoofing', question: 'Can an attacker impersonate a legitimate user or system component?' },
  { id: 'T', name: 'Tampering', question: 'Can an attacker modify data in transit or at rest without detection?' },
  { id: 'R', name: 'Repudiation', question: 'Can an attacker deny performing a security-relevant action?' },
  { id: 'I', name: 'Information Disclosure', question: 'Can an attacker access data they are not authorized to see?' },
  { id: 'D', name: 'Denial of Service', question: 'Can an attacker disrupt service availability for legitimate users?' },
  { id: 'E', name: 'Elevation of Privilege', question: 'Can an attacker gain higher privileges than originally granted?' }
];

const archComponents = architecture
  ? (Array.isArray(architecture) ? architecture : [architecture])
  : ['web-app', 'api', 'database'];
const analysisScope = scope || 'full';

const findings = [];

archComponents.forEach(component => {
  strideCategories.forEach(cat => {
    const finding = {
      id: cat.id + '-' + component + '-' + Date.now(),
      category: cat.name,
      categoryId: cat.id,
      component: component,
      question: cat.question,
      scope: analysisScope
    };

    if (analysisScope === 'architecture' || analysisScope === 'full') {
      if (component.includes('api') && cat.id === 'S') {
        finding.architectureRisk = 'high';
        finding.detail = 'API endpoints require robust authentication to prevent identity spoofing';
      } else if (component.includes('database') && cat.id === 'I') {
        finding.architectureRisk = 'high';
        finding.detail = 'Database access must enforce row-level security and encrypted connections';
      } else if (component.includes('web') && cat.id === 'T') {
        finding.architectureRisk = 'medium';
        finding.detail = 'Client-side data can be tampered with; validate all inputs server-side';
      } else if (cat.id === 'D') {
        finding.architectureRisk = 'medium';
        finding.detail = 'Component needs rate limiting and resource quotas';
      } else {
        finding.architectureRisk = 'low';
        finding.detail = 'Standard security controls apply';
      }
    }

    if (analysisScope === 'dependencies' || analysisScope === 'full') {
      if (cat.id === 'I' || cat.id === 'E') {
        finding.dependencyRisk = 'medium';
        finding.depDetail = 'Third-party dependencies may introduce information leaks or privilege escalation vectors';
      } else {
        finding.dependencyRisk = 'low';
        finding.depDetail = 'Low dependency-related risk for this category';
      }
    }

    findings.push(finding);
  });
});

return [{
  json: {
    projectId,
    runId,
    scope: analysisScope,
    architecture: archComponents,
    findings,
    analyzedAt: new Date().toISOString()
  }
}];

const data = $json;
const findings = data.findings || [];

const severityMap = { high: 3, medium: 2, low: 1 };

const ratedFindings = findings.map(f => {
  const archRisk = severityMap[f.architectureRisk] || 0;
  const depRisk = severityMap[f.dependencyRisk] || 0;
  const maxRisk = Math.max(archRisk, depRisk);

  let severity = 'low';
  if (maxRisk >= 3) severity = 'critical';
  else if (maxRisk >= 2) severity = 'high';
  else if (maxRisk >= 1) severity = 'medium';

  if (f.categoryId === 'E' && f.component.includes('api')) severity = 'critical';
  if (f.categoryId === 'I' && f.component.includes('database')) severity = 'critical';
  if (f.categoryId === 'S' && f.component.includes('api') && severity !== 'critical') severity = 'high';

  return {
    ...f,
    severity,
    riskScore: maxRisk,
    mitigationRequired: severity === 'critical' || severity === 'high'
  };
});

const criticalCount = ratedFindings.filter(f => f.severity === 'critical').length;
const highCount = ratedFindings.filter(f => f.severity === 'high').length;
const mediumCount = ratedFindings.filter(f => f.severity === 'medium').length;

let overallRisk = 'low';
if (criticalCount > 0) overallRisk = 'critical';
else if (highCount > 2) overallRisk = 'high';
else if (highCount > 0) overallRisk = 'medium';

return [{
  json: {
    ...data,
    findings: ratedFindings,
    summary: {
      criticalCount,
      highCount,
      mediumCount,
      totalFindings: ratedFindings.length
    },
    overallRisk,
    hasCritical: criticalCount > 0
  }
}];
